5516       !match(Phi->getOperand(1u),
5517              m_OneUse(m_Shuffle(m_Specific(Op), m_Poison(), m_Mask(Mask1)))))
5518     return false;
5519 
5520   auto *Shuf = cast<ShuffleVectorInst>(Phi->getOperand(0u));
5521 
5522   // Ensure result vectors are wider than the argument vector.
5523   auto *InputVT = cast<FixedVectorType>(Op->getType());
5524   auto *ResultVT = cast<FixedVectorType>(Shuf->getType());
5525   auto const InputNumElements = InputVT->getNumElements();
5526 
5527   if (InputNumElements >= ResultVT->getNumElements())
5528     return false;
5529 
5530   // Take the difference of the two shuffle masks at each index. Ignore poison
5531   // values at the same index in both masks.
5532   SmallVector<int, 16> NewMask;
5533   NewMask.reserve(Mask0.size());
