5535   for (auto [M0, M1] : zip(Mask0, Mask1)) {
5536     if (M0 >= 0 && M1 >= 0)
5537       NewMask.push_back(M0 - M1);
5538     else if (M0 == -1 && M1 == -1)
5539       continue;
5540     else
5541       return false;
5542   }
5543 
5544   // Ensure all elements of the new mask are equal. If the difference between
5545   // the incoming mask elements is the same, the two must be constant offsets
5546   // of one another.
5547   if (NewMask.empty() || !all_equal(NewMask))
5548     return false;
