5564                TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask1, CostKind));
5565   auto NewCost = TTI.getShuffleCost(Kind, InputVT, InputVT, NewMask, CostKind) +
5566                  TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask1, CostKind);
